namespace NotificationApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 4;
    private readonly Lock _lock = new();

    // Seed data available immediately for prerender.
    private readonly List<Notification> _notifications =
    [
        new(1, "Welcome to NotificationApp!", DateTime.UtcNow.AddMinutes(-10)),
        new(2, "Your profile was updated.", DateTime.UtcNow.AddMinutes(-5)),
        new(3, "New feature: dark mode is available.", DateTime.UtcNow.AddMinutes(-1)),
    ];

    /// <summary>Returns all current notifications (used for initial load).</summary>
    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_notifications.ToList());
        }
    }

    /// <summary>Returns notifications created after the given timestamp.</summary>
    public Task<List<Notification>> GetNotificationsSinceAsync(DateTime since)
    {
        // Simulate a new notification arriving roughly every 10 seconds.
        lock (_lock)
        {
            if (Random.Shared.Next(2) == 0)
            {
                var id = _nextId++;
                _notifications.Add(new Notification(
                    id,
                    $"New event #{id} just happened.",
                    DateTime.UtcNow));
            }

            return Task.FromResult(
                _notifications.Where(n => n.Timestamp > since).ToList());
        }
    }
}

