+@page "/notifications"
+@rendermode InteractiveServer
+@using NotificationApp.Services
+@inject NotificationService NotificationService
+@implements IAsyncDisposable
+
+<PageTitle>Notifications</PageTitle>
+
+<h1>
+    Notifications
+    @if (notifications is not null)
+    {
+        <span class="badge bg-primary rounded-pill ms-2">@notifications.Count</span>
+    }
+</h1>
+
+@if (notifications is null)
+{
+    <p><em>Loading notifications…</em></p>
+}
+else if (notifications.Count == 0)
+{
+    <p>No notifications yet.</p>
+}
+else
+{
+    <ul class="list-group">
+        @foreach (var n in notifications.OrderByDescending(x => x.Timestamp))
+        {
+            <li class="list-group-item d-flex justify-content-between align-items-start">
+                <span>@n.Message</span>
+                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
+            </li>
+        }
+    </ul>
+}
+
+@code {
+    private CancellationTokenSource? _cts;
+    private DateTime _lastCheck;
+
+    // Persisted across prerender → interactive so the initial fetch isn't repeated.
+    [PersistentState]
+    public List<Notification>? notifications { get; set; }
+
+    protected override async Task OnInitializedAsync()
+    {
+        // ??= ensures data fetched during prerender is reused on interactive activation.
+        notifications ??= await NotificationService.GetNotificationsAsync();
+        _lastCheck = notifications.Count > 0
+            ? notifications.Max(n => n.Timestamp)
+            : DateTime.UtcNow;
+    }
+
+    // OnAfterRenderAsync is NOT called during prerender — safe to start polling here.
+    protected override async Task OnAfterRenderAsync(bool firstRender)
+    {
+        if (firstRender)
+        {
+            _cts = new CancellationTokenSource();
+            _ = PollForNotificationsAsync(_cts.Token);
+        }
+
+        await base.OnAfterRenderAsync(firstRender);
+    }
+
+    private async Task PollForNotificationsAsync(CancellationToken ct)
+    {
+        while (!ct.IsCancellationRequested)
+        {
+            try
+            {
+                await Task.Delay(TimeSpan.FromSeconds(5), ct);
+
+                var newItems = await NotificationService.GetNotificationsSinceAsync(_lastCheck);
+                if (newItems.Count > 0)
+                {
+                    notifications!.AddRange(newItems);
+                    _lastCheck = newItems.Max(n => n.Timestamp);
+                    await InvokeAsync(StateHasChanged);
+                }
+            }
+            catch (OperationCanceledException)
+            {
+                break;
+            }
+        }
+    }
+
+    public async ValueTask DisposeAsync()
+    {
+        if (_cts is not null)
+        {
+            await _cts.CancelAsync();
+            _cts.Dispose();
+        }
+    }
+}
